// ============================================================
// src/components/VoteScreen.jsx
// Shows all descriptions + voting UI
// ============================================================
import React, { useState, useEffect } from "react";
import socket from "../socket";

export default function VoteScreen({ game, player, voteData, onResult }) {
  const [votedFor, setVotedFor]     = useState(null);
  const [voteCount, setVoteCount]   = useState({ voted: 0, total: 0 });
  const [timeLeft, setTimeLeft]     = useState(30);

  useEffect(() => {
    socket.on("voteUpdate",    (data) => setVoteCount(data));
    socket.on("voteTimerTick", ({ secondsLeft }) => setTimeLeft(secondsLeft));
    socket.on("roundResult",   (data) => onResult(data));
    return () => {
      socket.off("voteUpdate");
      socket.off("voteTimerTick");
      socket.off("roundResult");
    };
  }, [onResult]);

  const handleVote = (targetId) => {
    if (votedFor) return;
    setVotedFor(targetId);
    socket.emit("castVote", {
      code: game.code,
      voterId: player._id,
      targetId,
    });
  };

  const timerColor = timeLeft > 15 ? "#2ec4b6" : timeLeft > 5 ? "#f4a261" : "#e63946";

  return (
    <div className="screen">
      {/* Top bar */}
      <header className="topbar">
        <span className="logo-sm">IMPOSTOR<span>·X</span></span>
        <span className="round-badge">Round {voteData.round} — VOTE</span>
        <span className="timer-display" style={{ color: timerColor }}>⏱ {timeLeft}s</span>
      </header>
      <div className="timer-track">
        <div className="timer-fill" style={{ width: `${(timeLeft/30)*100}%`, background: timerColor }} />
      </div>

      <div className="vote-layout">
        {/* Descriptions panel */}
        <div className="card desc-panel">
          <h3 className="section-lbl">📋 Descriptions this round</h3>
          <ul className="desc-list">
            {voteData.descriptions.map((d, i) => (
              <li key={i} className="desc-item">
                <span className="desc-author">{d.name}</span>
                <span className="desc-text">"{d.text}"</span>
              </li>
            ))}
          </ul>
        </div>

        {/* Vote panel */}
        <div className="card vote-panel">
          <h3 className="section-lbl">👎 Who is the impostor?</h3>
          <p className="muted">{voteData.voted || voteCount.voted} / {voteData.total || voteCount.total} voted</p>

          {votedFor ? (
            <div className="voted-state">
              <div className="check-icon">✓</div>
              <p>Vote cast! Waiting for others…</p>
              <div className="dot-loader"><span/><span/><span/></div>
            </div>
          ) : (
            <ul className="vote-list">
              {voteData.players
                .filter(p => p._id !== player._id)
                .map(p => (
                  <li key={p._id}>
                    <button
                      className={`vote-btn ${votedFor === p._id ? "voted" : ""}`}
                      onClick={() => handleVote(p._id)}
                    >
                      <span className="av sm">{p.name[0].toUpperCase()}</span>
                      {p.name}
                      <span className="vote-arrow">→ Vote</span>
                    </button>
                  </li>
                ))
              }
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}
